<?php
namespace App\Domain\Media\EquipmentLayers;
use App\Domain\Characters\Appearance\CharacterVisualLayerOrder;use App\Domain\Characters\Appearance\ItemVisualSlotResolver;use App\Domain\Media\MediaAssetType;use App\Models\CharacterTemplate;use App\Models\Item;use App\Models\ItemVisualAsset;use App\Models\MediaAsset;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Log;use Illuminate\Support\Facades\Storage;use Illuminate\Support\Str;use Throwable;
final class EquipmentLayerAssetService{const DISK='public';const WIDTH=512;const HEIGHT=768;const MAX_BYTES=5242880;private $slots;public function __construct(ItemVisualSlotResolver $slots){$this->slots=$slots;}public function adminData(Item $item){$assets=$item->exists?$item->visualAssets()->with('mediaAsset')->orderBy('body_type')->orderBy('visual_slot')->get():collect();return['enabled'=>$item->exists&&!empty($this->slots->allowedSlots($item)),'body_types'=>CharacterTemplate::whereNotNull('body_type')->where('body_type','<>','')->distinct()->orderBy('body_type')->pluck('body_type')->values()->all(),'slots'=>$this->slots->allowedSlots($item),'slot_labels'=>CharacterVisualLayerOrder::labels(),'assets'=>$assets];}public function replace(Item $item,$bodyType,$visualSlot,UploadedFile $file){$this->assertAssignment($item,$bodyType,$visualSlot);$info=$this->inspect($file);$root='game-assets/equipment-layers/'.date('Y/m').'/'.Str::uuid();$path=$root.'/layer.'.$info['extension'];Storage::disk(self::DISK)->put($path,file_get_contents($file->getRealPath()));$old=null;try{$asset=DB::transaction(function()use($item,$bodyType,$visualSlot,$file,$info,$path,&$old){$locked=Item::whereKey($item->id)->lockForUpdate()->firstOrFail();$this->assertAssignment($locked,$bodyType,$visualSlot);$link=ItemVisualAsset::where('item_id',$locked->id)->where('body_type',$bodyType)->where('visual_slot',$visualSlot)->lockForUpdate()->first();$old=$link?$link->mediaAsset:null;$asset=$locked->mediaAssets()->create(['asset_type'=>MediaAssetType::EQUIPMENT_LAYER,'disk'=>self::DISK,'path'=>$path,'mime_type'=>$info['mime'],'width'=>self::WIDTH,'height'=>self::HEIGHT,'file_size'=>(int)$file->getSize(),'metadata'=>['equipment_layer_version'=>1,'body_type'=>$bodyType,'visual_slot'=>$visualSlot,'canvas'=>['width'=>self::WIDTH,'height'=>self::HEIGHT,'ratio'=>'2:3'],'original_name'=>$file->getClientOriginalName()],'is_primary'=>false,'sort_order'=>CharacterVisualLayerOrder::orderForSlot($visualSlot)]);if($link){$link->media_asset_id=$asset->id;$link->save();}else ItemVisualAsset::create(['item_id'=>$locked->id,'media_asset_id'=>$asset->id,'body_type'=>$bodyType,'visual_slot'=>$visualSlot]);return$asset;},3);}catch(Throwable $e){Storage::disk(self::DISK)->deleteDirectory($root);throw$e;}if($old)$this->removeCommittedAsset($old);return$asset;}public function delete(Item $item,ItemVisualAsset $link){if((int)$link->item_id!==(int)$item->id)throw new EquipmentLayerException('La capa no pertenece al objeto.');$asset=DB::transaction(function()use($link){$locked=ItemVisualAsset::whereKey($link->id)->lockForUpdate()->firstOrFail();$asset=$locked->mediaAsset;$locked->delete();if($asset)$asset->delete();return$asset;},3);if($asset)$this->deletePhysical($asset);}private function assertAssignment(Item $item,$bodyType,$slot){if(!is_string($bodyType)||$bodyType===''||!CharacterTemplate::where('body_type',$bodyType)->exists())throw new EquipmentLayerException('El tipo corporal no existe.');try{$this->slots->assertAllowed($item,$slot);}catch(Throwable $e){throw new EquipmentLayerException($e->getMessage());}}private function inspect(UploadedFile $file){if(!$file->isValid()||(int)$file->getSize()>self::MAX_BYTES)throw new EquipmentLayerException('La capa no es valida o supera 5 MB.');$info=@getimagesize($file->getRealPath());if(!$info||(int)$info[0]!==self::WIDTH||(int)$info[1]!==self::HEIGHT)throw new EquipmentLayerException('La capa debe medir exactamente 512 x 768 px.');$map=['image/png'=>['imagecreatefrompng','png'],'image/webp'=>['imagecreatefromwebp','webp']];$mime=isset($info['mime'])?$info['mime']:null;if(!isset($map[$mime]))throw new EquipmentLayerException('Solo se permiten capas PNG o WebP.');$image=@call_user_func($map[$mime][0],$file->getRealPath());if(!$image)throw new EquipmentLayerException('La capa no se puede decodificar.');imagedestroy($image);if($mime==='image/png'){$bytes=file_get_contents($file->getRealPath(),false,null,25,1);$type=$bytes===''?-1:ord($bytes);if(!in_array($type,[4,6],true))throw new EquipmentLayerException('El PNG debe incluir canal alfa.');}return['mime'=>$mime,'extension'=>$map[$mime][1]];}private function removeCommittedAsset(MediaAsset $asset){try{$path=$asset->path;$disk=$asset->disk;$asset->delete();Storage::disk($disk)->delete($path);}catch(Throwable $e){Log::warning('No se pudo limpiar una capa reemplazada.',['media_asset_id'=>$asset->id]);}}private function deletePhysical(MediaAsset $asset){try{Storage::disk($asset->disk)->delete($asset->path);}catch(Throwable $e){Log::warning('No se pudo eliminar el archivo de una capa.',['media_asset_id'=>$asset->id]);}}}
